import json,sys,urllib.request,urllib.error
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def req(u):
    try:
        r=urllib.request.urlopen(urllib.request.Request(B+u,headers={'X-N8N-API-KEY':K}),timeout=40)
        return r.status, r.read()
    except urllib.error.HTTPError as e:
        return e.code, e.read()
st,body=req('workflows?limit=250')
print('list HTTP',st)
if st==200:
    d=json.loads(body); ws=d.get('data') if isinstance(d,dict) else d
    for w in ws:
        nm=w.get('name','')
        if any(x in nm for x in ['Дашборд','Вітрин','Maersk (CRM)','дашборд']):
            print(('ON ' if w.get('active') else 'off'), w.get('id'),'|',nm)
# точкові GET
for wid in ['1YdXnLFOXI85IsWv','JQKA35haUsXU4XqE','VGi9phda7zLZC9eD']:
    s,_=req('workflows/'+wid); print('GET',wid,'->',s)
